#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
int solve(vector<vector<int>>& grid) {
  if (grid.size() == 0 || grid[0].size() == 0) return 0;
  const int n = grid.size(), m = grid[0].size();
  vector<int> dp(m);
  dp[0] = 1;
  for (int j = 1; j < m; j++)
    dp[j] = dp[j-1];
  for (int i = 1; i < n; i++)
    for (int j = 0; j < m; j++)
      dp[j] = (grid[i-1][j] == 0 && (j == 0 || grid[i-1][j-1] == 0)) ? dp[j-1] : 0;
  int res = 0;
  for (int j = 0; j < m; j++)
    if (grid[n-1][j] == 0) res += dp[j];
  return res;
}
};

int main() {
  ios_base::sync_with_stdio(false);
  cin.tie(nullptr);
  int n, m;
  cin >> n >> m;
  vector<vector<int>> grid(n, vector<int>(m));
  for (int i = 0; i < n; i++)
    for (int j = 0; j < m; j++)
      cin >> grid[i][j];
  Solution sol;
  cout << sol.solve(grid) << endl;
  return 0;
}

